import { Request, Response } from 'express';
import { validateState, exchangeCode } from './oauth-utils';
import { createSession } from '../session/manager';
import { OAuthProvider } from './providers';
import crypto from 'crypto';

export async function handleOAuthCallback(req: Request, res: Response) {
  const { code, state } = req.query;

  // Validate the OAuth state parameter to prevent CSRF
  if (!state || !validateState(req.session.oauthState, state as string)) {
    return res.status(403).json({ error: 'Invalid OAuth state' });
  }

  try {
    const provider = req.params.provider as OAuthProvider;
    const tokens = await exchangeCode(provider, code as string);

    // Create new session with tokens
    const session = await createSession({
      accessToken: tokens.access_token,
      refreshToken: tokens.refresh_token,
      userId: tokens.user_id,
      expiresIn: tokens.expires_in,
    });

    // Set session cookie
    res.cookie('session_id', session.id, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: session.expiresIn * 1000,
    });

    // Clear OAuth state
    delete req.session.oauthState;

    return res.redirect(req.session.returnTo || '/dashboard');
  } catch (error) {
    console.error('OAuth callback error:', error);
    return res.status(500).json({ error: 'Authentication failed' });
  }
}
